import { apiClient, unwrap, type BffResponse } from '../api';

export interface FormOption {
  value: string;
  label: string;
}

/** Toolbar flags from GET /forms/init-data — Package permissions. */
export interface FormActionPermissions {
  canCreate: boolean;
  canUpdate: boolean;
  canDelete: boolean;
  canApprove: boolean;
  canViewLedger: boolean;
  canPrint: boolean;
  canCopy: boolean;
  /** Hủy ghi sổ / hạ mức trên Posted — BE <c>erp-finance:receipts:unpost</c> hoặc :approve */
  canUnpost?: boolean;
}

export interface CurrencyExchangeRate {
  currencyCode: string;
  exchangeRate: number;
}

export interface AccountDefaultDto {
  code: string;
  name: string;
}

/** PT/PC — định khoản nghiệp vụ (LOOKUP_STATIC). */
export interface PostingReasonInitItem {
  code: string;
  name: string;
  debitAccountCode: string;
  creditAccountCode: string;
  erpDebitAccountCode?: string | null;
  erpCreditAccountCode?: string | null;
  allowEditPostingAccounts: boolean;
}

/** PT/PC — kênh thanh toán (LOOKUP_STATIC). */
export interface PaymentChannelInitItem {
  code: string;
  name: string;
  debitAccountCode: string;
}

export interface ErpFormInitData {
  materialGroupOptions: FormOption[];
  partnerGroupOptions: FormOption[];
  unitOptions: FormOption[];
  taxRateOptions: FormOption[];
  currencyOptions: FormOption[];
  warehouseOptions: FormOption[];
  departmentOptions: FormOption[];
  voucherStatusOptions: FormOption[];
  purchaseInvoiceTypeOptions: FormOption[];
  processingLevelOptions: FormOption[];
  defaultProcessingLevel?: string;
  defaultCurrencyCode?: string;
  defaultExchangeRate?: string;
  currencyExchangeRates?: CurrencyExchangeRate[];
  receiptKindOptions: FormOption[];
  customerGroupOptions: FormOption[];
  defaultAccount?: AccountDefaultDto;
  defaultCreditAccount?: AccountDefaultDto;
  defaultVatAccount?: AccountDefaultDto;
  defaultDebitAccount?: AccountDefaultDto;
  defaultFixedAssetAccount?: AccountDefaultDto;
  defaultDepreciationExpenseAccount?: AccountDefaultDto;
  defaultAccumDepreciationAccount?: AccountDefaultDto;
  journalEntryTypeOptions: FormOption[];
  formPermissions?: FormActionPermissions | null;
  postingReasonRules: PostingReasonInitItem[];
  paymentChannels: PaymentChannelInitItem[];
}

interface BffErpFormInitDataDto {
  materialGroupOptions?: FormOption[];
  partnerGroupOptions?: FormOption[];
  unitOptions?: FormOption[];
  taxRateOptions?: FormOption[];
  currencyOptions?: FormOption[];
  warehouseOptions?: FormOption[];
  departmentOptions?: FormOption[];
  voucherStatusOptions?: FormOption[];
  purchaseInvoiceTypeOptions?: FormOption[];
  processingLevelOptions?: FormOption[];
  defaultProcessingLevel?: string;
  defaultCurrencyCode?: string;
  defaultExchangeRate?: string;
  currencyExchangeRates?: CurrencyExchangeRate[];
  receiptKindOptions?: FormOption[];
  customerGroupOptions?: FormOption[];
  defaultAccount?: AccountDefaultDto;
  defaultCreditAccount?: AccountDefaultDto;
  defaultVatAccount?: AccountDefaultDto;
  defaultDebitAccount?: AccountDefaultDto;
  defaultFixedAssetAccount?: AccountDefaultDto;
  defaultDepreciationExpenseAccount?: AccountDefaultDto;
  defaultAccumDepreciationAccount?: AccountDefaultDto;
  journalEntryTypeOptions?: FormOption[];
  formPermissions?: FormActionPermissions | null;
  postingReasonRules?: PostingReasonInitItem[];
  paymentChannels?: PaymentChannelInitItem[];
}

const mapOpts = (items?: FormOption[]): FormOption[] =>
  (items ?? []).map(o => ({ value: o.value, label: o.label }));

const emptyInit = (): ErpFormInitData => ({
  materialGroupOptions: [],
  partnerGroupOptions: [],
  unitOptions: [],
  taxRateOptions: [],
  currencyOptions: [],
  warehouseOptions: [],
  departmentOptions: [],
  voucherStatusOptions: [],
  purchaseInvoiceTypeOptions: [],
  processingLevelOptions: [],
  receiptKindOptions: [],
  customerGroupOptions: [],
  journalEntryTypeOptions: [],
  postingReasonRules: [],
  paymentChannels: [],
});

const _cache = new Map<string, Promise<ErpFormInitData>>();

const _fetchInitData = async (formName: string): Promise<ErpFormInitData> => {
  const res = await apiClient.get<BffResponse<BffErpFormInitDataDto>>(
    `/forms/init-data?formName=${encodeURIComponent(formName)}`,
  );
  const dto = unwrap(res);
  return {
    materialGroupOptions: mapOpts(dto.materialGroupOptions),
    partnerGroupOptions: mapOpts(dto.partnerGroupOptions),
    unitOptions: mapOpts(dto.unitOptions),
    taxRateOptions: mapOpts(dto.taxRateOptions),
    currencyOptions: mapOpts(dto.currencyOptions),
    warehouseOptions: mapOpts(dto.warehouseOptions),
    departmentOptions: mapOpts(dto.departmentOptions),
    voucherStatusOptions: mapOpts(dto.voucherStatusOptions),
    purchaseInvoiceTypeOptions: mapOpts(dto.purchaseInvoiceTypeOptions),
    processingLevelOptions: mapOpts(dto.processingLevelOptions),
    defaultProcessingLevel: dto.defaultProcessingLevel,
    defaultCurrencyCode: dto.defaultCurrencyCode,
    defaultExchangeRate: dto.defaultExchangeRate,
    currencyExchangeRates: (dto.currencyExchangeRates ?? []).map(r => ({
      currencyCode: r.currencyCode,
      exchangeRate: Number(r.exchangeRate) || 1,
    })),
    receiptKindOptions: mapOpts(dto.receiptKindOptions),
    customerGroupOptions: mapOpts(dto.customerGroupOptions),
    journalEntryTypeOptions: mapOpts(dto.journalEntryTypeOptions),
    defaultAccount: dto.defaultAccount,
    defaultCreditAccount: dto.defaultCreditAccount,
    defaultVatAccount: dto.defaultVatAccount,
    defaultDebitAccount: dto.defaultDebitAccount,
    defaultFixedAssetAccount: dto.defaultFixedAssetAccount,
    defaultDepreciationExpenseAccount: dto.defaultDepreciationExpenseAccount,
    defaultAccumDepreciationAccount: dto.defaultAccumDepreciationAccount,
    formPermissions: dto.formPermissions ?? null,
    postingReasonRules: (dto.postingReasonRules ?? []).map(r => ({
      code: r.code,
      name: r.name,
      debitAccountCode: r.debitAccountCode ?? '',
      creditAccountCode: r.creditAccountCode ?? '',
      erpDebitAccountCode: r.erpDebitAccountCode,
      erpCreditAccountCode: r.erpCreditAccountCode,
      allowEditPostingAccounts: r.allowEditPostingAccounts === true,
    })),
    paymentChannels: (dto.paymentChannels ?? []).map(ch => ({
      code: ch.code,
      name: ch.name,
      debitAccountCode: ch.debitAccountCode ?? '',
    })),
  };
};

export const voucherInitService = {
  getInitData: (formName: string): Promise<ErpFormInitData> => {
    if (!_cache.has(formName)) {
      _cache.set(
        formName,
        _fetchInitData(formName).catch(err => {
          _cache.delete(formName);
          return Promise.reject(err);
        }),
      );
    }
    return _cache.get(formName)!;
  },
  clearCache: () => _cache.clear(),
};

export { emptyInit };
